function receiptTemplate(appName: string): string {
  return `// prodify-layer/email/templates/receipt.tsx
// Generated by Prodify — Payment receipt email template (React Email)
// Trigger this from the checkout.session.completed webhook handler.
import {
  Html, Head, Body, Container, Section,
  Heading, Text, Button, Hr, Row, Column,
} from '@react-email/components';
import * as React from 'react';

interface ReceiptEmailProps {
  userName?: string;
  amount?: string;        // formatted, e.g. "$19.00"
  planName?: string;      // e.g. "Pro — Monthly"
  receiptUrl?: string;    // Stripe-hosted receipt URL from checkout.session
  dashboardUrl?: string;
}

export function ReceiptEmail({
  userName = 'there',
  amount = '--',
  planName = '${appName} Pro',
  receiptUrl,
  dashboardUrl = process.env.NEXT_PUBLIC_APP_URL ?? 'http://localhost:3000',
}: ReceiptEmailProps) {
  return (
    <Html>
      <Head />
      <Body style={{ backgroundColor: '#f6f9fc', fontFamily: 'sans-serif' }}>
        <Container style={{ maxWidth: '600px', margin: '0 auto', padding: '40px 20px' }}>
          <Heading style={{ color: '#1a1b2e', fontSize: '24px' }}>
            Payment confirmed ✓
          </Heading>
          <Text style={{ color: '#555', fontSize: '16px' }}>
            Thanks {userName}! Your payment was successful.
          </Text>
          <Section style={{ background: '#fff', borderRadius: '8px', padding: '24px', margin: '24px 0', border: '1px solid #e6ebf1' }}>
            <Row>
              <Column><Text style={{ color: '#999', margin: 0 }}>Plan</Text></Column>
              <Column style={{ textAlign: 'right' }}><Text style={{ fontWeight: '600', margin: 0 }}>{planName}</Text></Column>
            </Row>
            <Row>
              <Column><Text style={{ color: '#999', margin: 0 }}>Amount</Text></Column>
              <Column style={{ textAlign: 'right' }}><Text style={{ fontWeight: '600', margin: 0 }}>{amount}</Text></Column>
            </Row>
          </Section>
          <Section style={{ textAlign: 'center', margin: '24px 0' }}>
            <Button
              href={dashboardUrl}
              style={{ background: '#575efe', color: '#fff', padding: '12px 24px', borderRadius: '8px', textDecoration: 'none', fontWeight: '600' }}
            >
              Go to dashboard →
            </Button>
            {receiptUrl && (
              <Text style={{ marginTop: '12px' }}>
                <a href={receiptUrl} style={{ color: '#575efe' }}>View full receipt</a>
              </Text>
            )}
          </Section>
          <Hr style={{ borderColor: '#e6ebf1' }} />
          <Text style={{ color: '#999', fontSize: '12px' }}>
            ${appName} · This is a payment confirmation for your records.
          </Text>
        </Container>
      </Body>
    </Html>
  );
}

export default ReceiptEmail;
`;
}

// ── Public API ────────────────────────────────────────────────────────────────

export function buildEmailFiles(answers: ProdifyAnswers): FileEntry[] {
  const { appName } = answers;

  return [
    { relativePath: 'prodify-layer/email/client.ts',                    content: resendClient(appName) },
    { relativePath: 'prodify-layer/email/templates/welcome.tsx',        content: welcomeTemplate(appName) },
    { relativePath: 'prodify-layer/email/templates/trial-ending.tsx',   content: trialEndingTemplate(appName) },
    { relativePath: 'prodify-layer/email/templates/receipt.tsx',        content: receiptTemplate(appName) },
  ];
}
